#include <vector>
using namespace std;

void topoSort(int V, vector<int> adj[]) {
    vector<int> indeg(V,0);
    for(int i=0;i<V;i++)
        for(int v: adj[i]) indeg[v]++;

    queue<int> q;
    for(int i=0;i<V;i++)
        if(indeg[i]==0) q.push(i);

    while(!q.empty()) {
        int u=q.front(); q.pop();
        cout<<u<<" ";
        for(int v: adj[u])
            if(--indeg[v]==0) q.push(v);
    }
}

#include <vector>
using namespace std;

bool dfsCycle(int node, vector<int> adj[], vector<bool>& vis, vector<bool>& rec) {
    vis[node]=rec[node]=true;
    for(int v: adj[node]) {
        if(!vis[v] && dfsCycle(v,adj,vis,rec)) return true;
        else if(rec[v]) return true;
    }
    rec[node]=false;
    return false;
}
